mapper.select:
SELECT t1.ID, t1.PURCHASE_TITLE, t1.PURCHASE_NO, t1.SUPPLIER_ID, t1.SUPPLIER_NAME, t1.PURCHASE_TYPE_CODE, t1.PURCHASE_TYPE_NAME, t1.FIXED_SERVICE_CATEGORY_CODE, t1.FIXED_SERVICE_CATEGORY_NAME, t1.TAX_INCLUDED_AMOUNT, t1.TAX_EXCLUDED_AMOUNT, t1.PURCHASE_STATUS, t1.FAILURE_REASON, t1.APPROVAL_BY, t1.APPROVAL_BY_NAME, t1.APPROVAL_TIME, t1.APPROVAL_REMARK, t1.CREATE_BY, t1.CREATE_BY_NAME, t1.CREATE_TIME, t1.UPDATE_BY, t1.UPDATE_BY_NAME, t1.UPDATE_TIME, t3.PROC_INST_ID, CASE WHEN t3.INSTANCE_STATUS IS NULL THEN '0' ELSE t3.INSTANCE_STATUS END AS processStatus, CASE WHEN t2.DICT_LABEL IS NULL THEN '未发起' ELSE t2.DICT_LABEL END AS processStatusLabel FROM E_MATERIAL_PURCHASE t1 LEFT JOIN BPM_BUSINESS_INSTANCE t3 ON t3.BUSINESS_DATA_ID = t1.ID LEFT JOIN M_DICT_DATA t2 ON t2.DICT_VALUE = t3.INSTANCE_STATUS AND t2.DICT_TYPE = 'APPROVAL_STATUS'
AND t1.PURCHASE_NO LIKE #{purchaseNoPattern}
AND t1.PURCHASE_TITLE LIKE #{purchaseTitlePattern}
AND t1.SUPPLIER_ID = #{supplierId}
AND t1.SUPPLIER_NAME LIKE #{supplierNamePattern}
AND t1.PURCHASE_TYPE_CODE = #{purchaseTypeCode}
AND t1.PURCHASE_STATUS = #{purchaseStatus}
ORDER BY CREATE_TIME DESC

SELECT COUNT(*)
FROM E_MATERIAL_PURCHASE
WHERE PURCHASE_NO = #{purchaseNo}

    AND ID != #{id}
